INSERT INTO `Listing` (`id`, `rawId`, `source`, `url`, `title`, `description`, `price`, `pricePerSqm`, `currency`, `area`, `rooms`, `floor`, `totalFloors`, `yearBuilt`, `city`, `district`, `address`, `lat`, `lng`, `images`, `createdAt`, `updatedAt`, `condition`, `extras`, `hasBalcony`, `hasElevator`, `hasGarden`, `hasParking`, `heatingType`, `marketType`, `monthlyFee`, `propertyType`, `aiSummary`) VALUES (1061,1296,'otodom','https://www.otodom.pl/pl/oferta/poddaszedebowa-podlogaspokoj-i-cisza-ID4BTuO','✨Poddasze✨Dębowa Podłoga✨Spokój i cisza✨','Jasne, przestronna i klimatyczna kawalerka typu studio położona przy ul. Królewskiej 15E w Jabłonnie. Lokal znajduje się na kameralnym, nowym osiedlu z 2024 roku i został wykończony z dużą dbałością o...',NULL,NULL,'PLN',NULL,NULL,NULL,NULL,2024,'Jabłonna',NULL,'ul. Królewska 15E',NULL,NULL,'[\"https://ireland.apollo.olxcdn.com/v1/files/eyJmbiI6ImZxNnQ3MW1wN3lrNjEtRUNPU1lTVEVNIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNCIsInAiOiIxMCwtMTAiLCJhIjoiMCJ9XX0.oElPucu09rPHAoawKLhFfATq_822ic4AuYrU4_VSoDs/image;s=1280x1024;q=80\",\"https://ireland.apollo.olxcdn.com/v1/files/eyJmbiI6ImxnNXJicnF5M3hvYzEtRUNPU1lTVEVNIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNCIsInAiOiIxMCwtMTAiLCJhIjoiMCJ9XX0._4ULC5eVUrrSTpugXEmivP0mCLllkJLlpPsxYDW30w8/image;s=1280x1024;q=80\",\"https://ireland.apollo.olxcdn.com/v1/files/eyJmbiI6InZzeXh1b2NoMm44YTItRUNPU1lTVEVNIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNCIsInAiOiIxMCwtMTAiLCJhIjoiMCJ9XX0.50-fWprWJJ1eufIvC-NquKfczBD4ZFriuPfuKamLkQI/image;s=1280x1024;q=80\"]','2026-06-23 15:26:24.747','2026-06-23 15:26:24.747',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'primary',NULL,'studio','Oferowana kawalerka typu studio w Jabłonnie to jasne i przestronne mieszkanie, usytuowane w nowym, kameralnym osiedlu z 2024 roku. Wykończona z dużą dbałością o detale, zapewnia komfort oraz spokój, idealne dla osób szukających relaksu w cichej okolicy. Dębowa podłoga dodaje wnętrzu elegancji i przytulności.'),(1063,1304,'otodom','https://www.otodom.pl/pl/oferta/kawalerka-blisko-asp-do-wprowadzenia-doly-ID4BTuD','Kawalerka blisko Asp / do wprowadzenia / Doły','TYLKO U NAS<br><br>Na sprzedaż widna, przytulna kawalerka o powierzchni 21,59 m2 usytuowana na 3. piętrze w niskim bloku na Dołach. <br><br>Mieszkanie składa się z:<br>- jasnego pokoju dziennego z balkonem \"francuskim\",<br>- kuchni, <br>- łazienki, <br>- korytarza.<br>Do nieruchomości przynależy piwnica.<br>Dostępny jest parking ogólnodostępny dla mieszkańców ale również istnieje możliwość wynajmu miejsca parkingowego pod blokiem. <br><br>Lokal przeszedł generalny remont w 2019 roku.<br>Instalacje elektryczne oraz piony wodne są wymienione. <br>Sprzęty oraz meble w zabudowie widoczne na zdjęciach uwzględnione są w cenie.<br><br>Niewątpliwym atutem nieruchomości jest lokalizacja. <br>Doły to zielone i spokojne osiedle, które jest dobrze skomunikowane z każdą częścią miasta - zaledwie kilka kroków od budynku znajduje się przystanek autobusowy oraz tramwajowy.<br>W pobliżu znajduje się wiele terenów spacerowych - Park Ocalałych, Park im. Szarych Szeregów.<br>W niedalekiej odległości jest Akademia Sztuk Pięknych.<br>Dookoła jest wiele punktów usługowych, sklepy, markety, przychodnia, fryzjer.<br><br>Mieszkanie idealnie sprawdzi się jako pierwsze lokum dla singla, studenta lub jako inwestycja pod wynajem.<br><br>Zapraszam na prezentacje :)<br><br><br>',235000,10885,'PLN',21.59,1,3,4,1978,'lodz',NULL,NULL,NULL,NULL,'[\"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6ImZ1aDM1b3doaWZxdi1FQ09TWVNURU0iLCJ3IjpbeyJmbiI6ImVudmZxcWUxYXk0azEtQVBMIiwicyI6IjE2IiwiYSI6IjAiLCJwIjoiMTAsLTEwIn1dfQ.vmvsC2_pJKR9ofhJhicod-IXWW2OfhwbbCWWk8rJDvY/image;s=1280x1024;q=80\",\"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6Im9kYTZxeG5laGJiMzItRUNPU1lTVEVNIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0.IwO_alsR5vrv5INPLFMcRNdxuYT