0xMCJ9XX0.5jpKPb98HJaVmv9G_9jOmFmvNojr4SDfEcImpha6WKc/image;s=1280x1024;q=80\", \"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6Im94anE5aTZxdXRraC1BUEwiLCJ3IjpbeyJmbiI6ImVudmZxcWUxYXk0azEtQVBMIiwicyI6IjE2IiwiYSI6IjAiLCJwIjoiMTAsLTEwIn1dfQ.jrKPzjvCJCVRF7asoTyOcX7KdKr8DBlx6H0Qlf2CaJo/image;s=1280x1024;q=80\", \"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6ImdzdnRpYzZrNjFkejItQVBMIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0._0DSaqAAMHQTEhjav4ilA0nGN8w-h-s3BdIKeqJulkw/image;s=1280x1024;q=80\", \"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6InBmcjBuZTdhbWZ3OTMtQVBMIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0.c2eMe4BUOVvOpSur2FaTg0N-AynaS7MNdqrlmZjcPd4/image;s=1280x1024;q=80\", \"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6Ind4eGVjeHd3MzVhZjMtQVBMIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0.Qdjy7-qYu9Q19cqKoBFz0z_Q0LkTMNnx3pSPQ0gh8Is/image;s=1280x1024;q=80\", \"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6Imk1eHM0czV4azl5OTItQVBMIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0.vwpHUc2HQsrF995ijgq5bDsM37s3xeMz1BzyG7mU4W4/image;s=1280x1024;q=80\", \"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6ImUydDl3eWxxaTV6czMtQVBMIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0.SQvyShJf8r2h1e7IoWdC8Hes0fMST7b3kVUVyyFNIAM/image;s=1280x1024;q=80\"], \"address\": null, \"currency\": \"PLN\", \"district\": null, \"yearBuilt\": null, \"marketType\": null, \"description\": \"Mieszkanie z dużym potencjałem na Osiedlu Kopernika &ndash; Grudziądz, ul. Bydgoska 27Na sprzedaż funkcjonalne, dwustronne mieszkanie o powierzchni 39 m&sup2;, położone na parterze zadbanego bloku na ...\", \"pricePerSqm\": 6385, \"totalFloors\": null, \"propertyType\": \"FLAT\", \"characteristics\": \"area_m2: 39\\nprice_pln: 249000\\nrooms: 2\\nfloor: ground_floor\\nmarket: secondary\\nbuilding_type: block\\nextras: balcony\\ncity: grudziadz\\nlift: no\", \"fullDescription\": \"<p>Mieszkanie z dużym potencjałem na Osiedlu Kopernika &ndash; Grudziądz, ul. Bydgoska 27</p><p>Na sprzedaż funkcjonalne, dwustronne mieszkanie o powierzchni 39 m&sup2;, położone na parterze zadbanego bloku na spokojnym i kameralnym Osiedlu Kopernika w Grudziądzu.</p><p>Lokal składa się z:</p><p><ul><br/><li>dw&oacute;ch niezależnych pokoi,</li><br/><li>kuchni,</li><br/><li>łazienki,</li><br/><li>oddzielnej toalety,</li><br/><li>przedpokoju.</li><br/><li>z salonu wyjście na balkon</li><br/><li>do mieszkania przynależy piwnica&nbsp;</li><br/></ul></p><p>Mieszkanie jest czyste, zadbane i gotowe do zamieszkania, jednak ze względu na starszy styl wykończenia stanowi doskonałą propozycję dla os&oacute;b, kt&oacute;re chcą urządzić wnętrze według własnego gustu i potrzeb. W toalecie rozpoczęto już prace remontowe związane ze skuwaniem płytek, a w lokalu wykonano nowe piony wodno-kanalizacyjne.</p><p>Najważniejsze atuty nieruchomości:</p><p><ul><br/><li>powierzchnia 39 m&sup2;,</li><br/><li>parter,</li><br/><li>dwa niezależne pokoje,</li><br/><li>mieszkanie dwustronne,</li><br/><li>balkon,</li><br/><li>piwnica,</li><br/><li>księga wieczysta bez obciążeń hipotecznych,</li><br/><li>ogrzewanie miejskie,</li><br/><li>ciepłe mieszkanie z niskimi kosztami utrzymania,</li><br/><li>czynsz około 600 zł,</li><br/><li>zarządzane przez sp&oacute;łdzielnię mieszkaniową,</li><br/><li>duży, og&oacute;lnodostępny parking bezpośrednio przy budynku,</li><br/><li>spokojna i cicha lokalizacja.</li><br/></ul></p><p>Blok położony jest w głębi osiedla, dzięki czemu mieszkańcy mogą cieszyć się ciszą i prywatnością, jednocześnie mając pełną infrastrukturę miejską w zasięgu kilku minut spacerem.</p><p>W najbliższej okolicy znajdują się:</p><p><ul><br/><li>sklepy i markety, w tym market Hildebrandt,</li><br/><li>poczta,</li><br/><li>przychodnia,</li><br/><li>przystanki autobusowe i tramwajowe,</li><br/><li>kości&oacute;ł,</li><br/><li>basen,</li><br/><li>siłownia,</li><br/><li>szkoły i punkty usługowe.</li><br/></ul></p><p>To idealna propozycja zar&oacute;wno dla os&oacute;b szukających pierwszego mieszkania, senior&oacute;w ceniących parter, jak i inwestor&oacute;w poszukujących lokalu pod wynajem.</p><p>Zapraszam do kontaktu i um&oacute;wienia się na prezentację. Warto zobaczyć mieszkanie na żywo i przekonać się o jego potencjale.<br/><br/><br/>&nbsp; </p>\"}','2026-06-23 15:26:08.121'),(1369,'otodom','https://www.otodom.pl/pl/oferta/3pok-ip-2008r-os-mlodych-zamkniete-osiedle-ID4nC17',NULL,'{\"lat\": null, \"lng\": null, \"url\": \"https://www.otodom.pl/pl/oferta/3pok-ip-2008r-os-mlodych-zamkniete-osiedle-ID4nC17\", \"area\": 69.4, \"city\": \"Białystok\", \"slug\": \"3pok-ip-2008r-os-mlodych-zamkniete-osiedle-ID4nC17\", \"floor\": null, \"price\": 745000, \"rooms\": \"THREE\", \"title\": \"3pok | Ip | 2008r.|os. Młodych | zamknięte osiedle\", \"images\": [\"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6Inhxa3lsdW42NndtdzItQVBMIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0.ireCC7D9BtMSjxPF7YK_lHfQEqvBCEAfx6HDxk6Px7s/image;s=1280x1024;q=80\", \"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6Imtvb3doZ2Z6ejJiNTMtQVBMIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0.D7vMv2Ja06Mn6aFSwWJ_tbQgvaXK7LnKEZJUDsk9XJY/image;s=1280x1024;q=80\", \"https://ireland.apollo.olxcdn.com/v1/files/eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJmbiI6IjZ3NGVrbHd6dnU4MTItQVBMIiwidyI6W3siZm4iOiJlbnZmcXFlMWF5NGsxLUFQTCIsInMiOiIxNiIsImEiOiIwIiwicCI6IjEwLC0xMCJ9XX0.gS6uTULcZxU3SdLxwyiRTmwcYUu_XkbIFOUMgEGZF_A/image;s=1280